                                                const at::Tensor& w,
                                                const at::Tensor& b,
                                                const at::Tensor& scaling) {
    TORCH_CHECK(scaling.numel() == 1, \"'scaling' tensor must contain exactly one element\");
    double scale = scaling.item<double>();
    // Output shape: [M, N] where M = x.size(0), N = w.size(0)
    at::Tensor result = at::empty({x.size(0), w.size(0)}, x.options());
    // Pass scale as attribute to the custom op
    EXEC_NPU_CMD(aclnnMatmulScalingResidualAddCustom, x, w, b, scale, result);
    return result;
}

